    49→
    50→// DetectPresence checks if Gemini CLI is configured in the repository.
    51→func (g *GeminiCLIAgent) DetectPresence() (bool, error) {
    52→	// Get repo root to check for .gemini directory
    53→	// This is needed because the CLI may be run from a subdirectory
    54→	repoRoot, err := paths.RepoRoot()
    55→	if err != nil {
    56→		// Not in a git repo, fall back to CWD-relative check
    57→		repoRoot = "."
    58→	}
    59→
    60→	// Check for .gemini directory
    61→	geminiDir := filepath.Join(repoRoot, ".gemini")
    62→	if _, err := os.Stat(geminiDir); err == nil {
    63→		return true, nil
    64→	}
    65→	// Check for .gemini/settings.json
    66→	settingsFile := filepath.Join(repoRoot, ".gemini", "settings.json")
    67→	if _, err := os.Stat(settingsFile); err == nil {
    68→		return true, nil
    69→	}
    70→	return false, nil
    71→}
    72→
    73→// GetHookConfigPath returns the path to Gemini's hook config file.
    74→func (g *GeminiCLIAgent) GetHookConfigPath() string {
    75→	return ".gemini/settings.json"
    76→}
    77→
    78→// SupportsHooks returns true as Gemini CLI supports lifecycle hooks.
    79→func (g *GeminiCLIAgent) SupportsHooks() bool {
    80→	return true
    81→}
    82→
    83→// ParseHookInput parses Gemini CLI hook input from stdin.
    84→func (g *GeminiCLIAgent) ParseHookInput(hookType agent.HookType, reader io.Reader) (*agent.HookInput, error) {
    85→	data, err := io.ReadAll(reader)
    86→	if err != nil {
    87→		return nil, fmt.Errorf("failed to read input: %w", err)
    88→	}
    89→
    90→	if len(data) == 0 {
    91→		return nil, errors.New("empty input")
    92→	}
    93→
    94→	input := &agent.HookInput{
    95→		HookType:  hookType,
    96→		Timestamp: time.Now(),
    97→		RawData:   make(map[string]interface{}),
    98→	}
    99→
   100→	// Parse based on hook type
   101→	switch hookType {
   102→	case agent.HookSessionStart, agent.HookSessionEnd, agent.HookStop:
   103→		var raw sessionInfoRaw
   104→		if err := json.Unmarshal(data, &raw); err != nil {
   105→			return nil, fmt.Errorf("failed to parse session info: %w", err)
   106→		}
   107→		input.SessionID = raw.SessionID
   108→		input.SessionRef = raw.TranscriptPath
   109→		// Store Gemini-specific fields in RawData
   110→		input.RawData["cwd"] = raw.Cwd
   111→		input.RawData["hook_event_name"] = raw.HookEventName
   112→		if raw.Source != "" {
   113→			input.RawData["source"] = raw.Source
   114→		}
   115→		if raw.Reason != "" {
   116→			input.RawData["reason"] = raw.Reason
   117→		}
   118→
   119→	case agent.HookUserPromptSubmit:
   120→		// BeforeAgent is Gemini's equivalent to Claude's UserPromptSubmit
   121→		// It provides the user's prompt in the "prompt" field
   122→		var raw agentHookInputRaw
   123→		if err := json.Unmarshal(data, &raw); err != nil {
   124→			return nil, fmt.Errorf("failed to parse agent hook input: %w", err)
   125→		}
   126→		input.SessionID = raw.SessionID
   127→		input.SessionRef = raw.TranscriptPath
   128→		input.RawData["cwd"] = raw.Cwd
   129→		input.RawData["hook_event_name"] = raw.HookEventName
   130→		if raw.Prompt != "" {
   131→			input.UserPrompt = raw.Prompt
   132→			input.RawData["prompt"] = raw.Prompt
   133→		}
   134→
   135→	case agent.HookPreToolUse, agent.HookPostToolUse:
   136→		var raw toolHookInputRaw
   137→		if err := json.Unmarshal(data, &raw); err != nil {
   138→			return nil, fmt.Errorf("failed to parse tool hook input: %w", err)
   139→		}
   140→		input.SessionID = raw.SessionID
   141→		input.SessionRef = raw.TranscriptPath
   142→		input.ToolName = raw.ToolName
   143→		input.ToolInput = raw.ToolInput
   144→		if hookType == agent.HookPostToolUse {
   145→			input.ToolResponse = raw.ToolResponse
   146→		}
   147→		input.RawData["cwd"] = raw.Cwd
   148→		input.RawData["hook_event_name"] = raw.HookEventName
   149→	}
   150→
   151→	return input, nil
   152→}
   153→
   154→// GetSessionID extracts the session ID from hook input.
   155→func (g *GeminiCLIAgent) GetSessionID(input *agent.HookInput) string {
   156→	return input.SessionID
   157→}
   158→
   159→// ProtectedDirs returns directories that Gemini uses for config/state.
   160→func (g *GeminiCLIAgent) ProtectedDirs() []string { return []string{".gemini"} }
   161→
   162→// ResolveSessionFile returns the path to a Gemini session file.
   163→// Gemini names files as session-<date>-<shortid>.json where shortid is the first 8 chars
   164→// of the session UUID. This searches for an existing file matching the pattern, falling
   165→// back to <dir>/<id>.json if no match is found.
   166→func (g *GeminiCLIAgent) ResolveSessionFile(sessionDir, agentSessionID string) string {
   167→	// Try to find existing file matching Gemini's naming convention:
   168→	// session-*-<first8chars>.json
   169→	shortID := agentSessionID
   170→	if len(shortID) > 8 {
   171→		shortID = shortID[:8]
   172→	}
   173→
   174→	pattern := filepath.Join(sessionDir, "session-*-"+shortID+".json")
